form:Form.form:Scripts:
		function ONLOAD()
{
	if (Ctrl('main').GetMode() == 'NEW')
		return;

	var ult = 0;
	if (Ctrl('LIST'))
	{
		if (Ctrl('LIST').GetXValue() == Ctrl('LIST').GetAttrValue(Ctrl('LIST').TotalRowsCount()-1, 'id'))
		{
			ult = 1;
		}
	}	
	else
	{
		if (Ctrl('iter-position').GetXValue() == Ctrl('iter-size').GetXValue())
		{
			ult = 1;
		}
	}


 	CtrlEnabled('f_fin', false);
	CtrlEnabled('e_duracion', false);
	CtrlEnabled('oi_unidad_tiempo', false);
	CtrlEnabled('o_contrato_per', false);
	CtrlEnabled('DELETE', false);

	if (ult == 1)
	{
		CtrlEnabled('f_fin', true);
		CtrlEnabled('e_duracion', true);
		CtrlEnabled('oi_unidad_tiempo', true);
		CtrlEnabled('o_contrato_per', true);
		CtrlEnabled('DELETE', true);
	} 

}

function cambiaFechaInicio() {
	calculaDias();
}

function cambiaFechaFin() {
	calculaDias();
}

function calculaDias(){

	var fechaInicio = str2date(Ctrl('f_inicio').GetXValue());
	var fechaFin = str2date(Ctrl('f_fin').GetXValue());

		if(Ctrl('f_inicio').GetXValue()!='' && Ctrl('f_fin').GetXValue()!='' && fechaFin >= fechaInicio)
			{          
			if(traerIdDias()!='')
				{
				var dias = DiffDays(fechaFin, fechaInicio)+1;
				Ctrl('e_duracion').SetTypedValue(dias);
				Ctrl('oi_unidad_tiempo').SetXValue(traerIdDias());
				}
			}
		else
			{
			Ctrl('e_duracion').SetTypedValue('');
			Ctrl('oi_unidad_tiempo').SetXValue('');
			}

}     

//Devuelve el id de la unidad de tiempo días
function traerIdDias()
{
	var resultado;	

	var np = new NomadProxy("", ut);
	var nSQL = np.SQLService();

	resultado = nSQL.GetOBJ(Ctrl("main").getResource("QRY_UNI_TIEMPO"), "<PARAM c_unidad_tiempo=\'D\'/>"); 		
	if(resultado.oi_unidad_tiempo)
	{    
		return resultado.oi_unidad_tiempo; 	
	}
	else
	{       
		alert('No se puede hacer el calculo de la duración porque no se encontró la unidad de tiempo D - Días.');
		return '';
	}

}
